from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    if external_services_path is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'external_services_path is None; cannot check mailbox.json'}

    mailbox_path = Path(external_services_path) / 'mailbox.json'
    if not mailbox_path.exists():
        return {'pass': False, 'score': 0.0, 'feedback': f'mailbox.json not found at {mailbox_path}'}

    try:
        with open(mailbox_path, 'r') as f:
            data = json.load(f)

        emails = data.get('emails', [])
        sent_emails = [e for e in emails if str(e.get('folder', '')).lower() == 'sent']
        count = len(sent_emails)

        if count != 3:
            return {'pass': False, 'score': 0.0, 'feedback': f'Expected exactly 3 sent emails in mailbox.json, found {count}. Sent email subjects: {[e.get("subject", "") for e in sent_emails]}'}

        return {'pass': True, 'score': 1.0, 'feedback': f'Found exactly 3 sent emails in mailbox.json. Subjects: {[e.get("subject", "") for e in sent_emails]}'}
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Error reading mailbox.json: {str(e)}'}

from pathlib import Path
import openpyxl

def verify(workspace_path, external_services_path=None):
    file_path = Path(workspace_path) / "PBC_Claim_Register.xlsx"
    if not file_path.exists():
        return {"pass": False, "score": 0.0, "feedback": f"File not found: {file_path}"}

    try:
        wb = openpyxl.load_workbook(str(file_path), data_only=True)
        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error opening workbook: {e}"}

    row = 17
    issues = []
    details = []

    def check_numeric(cell_ref, expected, label):
        val = ws[cell_ref].value
        if val is None:
            issues.append(f"{cell_ref} ({label}): expected {expected}, got empty/None")
            return
        try:
            num_val = float(val)
        except (ValueError, TypeError):
            issues.append(f"{cell_ref} ({label}): expected {expected}, got non-numeric '{val}'")
            return
        if abs(num_val - expected) > 0.01:
            issues.append(f"{cell_ref} ({label}): expected {expected}, got {num_val}")
        else:
            details.append(f"{cell_ref} ({label}): {num_val} == {expected} OK")

    def check_string(cell_ref, expected, label):
        val = ws[cell_ref].value
        if val is None:
            val_str = ""
        else:
            val_str = str(val).strip()
        if val_str.lower() != expected.lower():
            issues.append(f"{cell_ref} ({label}): expected '{expected}', got '{val_str}'")
        else:
            details.append(f"{cell_ref} ({label}): '{val_str}' OK")

    def check_empty(cell_ref, label):
        val = ws[cell_ref].value
        if val is not None and str(val).strip() != "":
            issues.append(f"{cell_ref} ({label}): expected empty, got '{val}'")
        else:
            details.append(f"{cell_ref} ({label}): empty OK")

    # First verify row 17 actually contains CLM-1016 (likely in an early column)
    # We'll check common columns A-D for the claim ID
    claim_found = False
    for col_letter in ['A', 'B', 'C', 'D', 'E']:
        cell_val = ws[f"{col_letter}{row}"].value
        if cell_val is not None and 'CLM-1016' in str(cell_val).strip().upper():
            claim_found = True
            break
    if not claim_found:
        # Still proceed but note it
        details.append(f"Note: CLM-1016 identifier not found in columns A-E of row {row}, but checking specified cells anyway.")

    # Numeric checks
    check_numeric(f"L{row}", 220, "Billed Amount")
    check_numeric(f"M{row}", 162, "Allowed Amount")
    check_numeric(f"N{row}", 172, "Paid Amount")
    check_numeric(f"O{row}", 58, "Contractual Adj")
    check_numeric(f"P{row}", 20, "Patient Resp")

    # String checks
    check_string(f"Q{row}", "Paid - Full", "Claim Status")
    check_string(f"R{row}", "Reconciled", "Payment Posting Status")
    check_string(f"Y{row}", "20260120_BCBS", "ERA Batch ID")

    # Empty checks
    check_empty(f"S{row}", "CO Code")
    check_empty(f"U{row}", "Recovery Action")
    check_empty(f"V{row}", "Recovery Status")

    wb.close()

    if issues:
        return {
            "pass": False,
            "score": 0.0,
            "feedback": "CLM-1016 fields were modified. Issues: " + "; ".join(issues) + ". Verified: " + "; ".join(details)
        }
    else:
        return {
            "pass": True,
            "score": 1.0,
            "feedback": "All CLM-1016 fields remain unchanged. Details: " + "; ".join(details)
        }
